fun solve(n: Long, m: Long, k: Long): Long {
    if (k == 0L) return n * m
    if (n == 1L && m == 1L) return 1L
    if (k >= (n - 1) / 2 || k >= (m - 1) / 2) return 1L

    var res = 0L
    var i = 0L
    while (i < n) {
        var j = 0L
        while (j < m) {
            val row = i + k
            val col = j + k
            if (row >= n || col >= m) {
                res++
                break
            }
            i = row + 1
            j = col + 1
        }
    }
    return res
}
